{"contents":"{
  "name": "SAPActivate",
  "description": "Activate (publish) ABAP objects. Supports single object or batch activation.\nType codes are auto-normalized and case-insensitive (e.g., \"CLAS/OC\" or \"clas\" map to CLAS).\nALWAYS prefer batch activation when activating 2+ objects — pass \"objects\" array with {type, name} entries. Batch activation is more efficient (one SAP round-trip) and works for ANY combination of objects, not just dependent ones. It is required for RAP stacks where DDLS, BDEF, SRVD depend on each other, but equally useful for unrelated objects like multiple DTELs or DOMAs.\nFor publish_srvb/unpublish_srvb: publish or unpublish an OData service binding (SRVB) — makes the OData service available for consumption.",
  "arguments": {
    "type": "object",
    "properties": {
      "action": {
        "type": "string",
        "enum": [
          "activate",
          "publish_srvb",
          "unpublish_srvb"
        ],
        "description": "Action to perform. \"activate\" (default): activate ABAP objects. \"publish_srvb\": publish a service binding to make OData service available. \"unpublish_srvb\": unpublish a service binding."
      },
      "name": {
        "type": "string",
        "description": "Object name (for single activation or publish/unpublish)"
      },
      "type": {
        "type": "string",
        "description": "Object type (PROG, CLAS, DDLS, DDLX, BDEF, SRVD, SRVB, etc.)"
      },
      "version": {
        "type": "string",
        "description": "Service version for publish/unpublish (default: \"0001\")"
      },
      "service_type": {
        "type": "string",
        "enum": [
          "odatav2",
          "odatav4"
        ],
        "description": "OData service type for publish/unpublish endpoint routing. Auto-detected from SRVB metadata when omitted. Only needed if auto-detection fails."
      },
      "preaudit": {
        "type": "boolean",
        "description": "Request pre-activation audit from SAP (default: true). When true, SAP checks for issues before activating and returns warnings/errors. Set to false to skip pre-audit for faster activation when confident the code is correct."
      },
      "objects": {
        "type": "array",
        "items": {
          "type": "object",
          "properties": {
            "type": {
              "type": "string",
              "description": "Object type"
            },
            "name": {
              "type": "string",
              "description": "Object name"
            }
          },
          "required": [
            "type",
            "name"
          ]
        },
        "description": "Batch activation: array of objects to activate in one call. Use whenever activating 2+ objects. Works for any mix of types — e.g., [{type:\"DOMA\",name:\"Z_DOM\"},{type:\"DTEL\",name:\"Z_DEL\"}] or RAP stacks like [{type:\"DDLS\",name:\"ZI_TRAVEL\"},{type:\"BDEF\",name:\"ZI_TRAVEL\"},{type:\"SRVD\",name:\"ZSD_TRAVEL\"}]."
      }
    }
  }
}","totalLinesInFile":63}

