            },
            "url": {
              "type": "string"
            },
            "library_id": {
              "type": "string"
            },
            "topic": {
              "type": "string"
            },
            "snippet": {
              "type": "string"
            },
            "score": {
              "type": "number"
            },
            "metadata": {
