{"contents":"{
  "name": "run_manifest_validation",
  "description": "Validates UI5 manifest file. After making changes, you should always run the validation again to verify that no new problems have been introduced.",
  "arguments": {
    "type": "object",
    "properties": {
      "manifestPath": {
        "type": "string",
        "description": "Absolute path to the manifest file to validate."
      }
    },
    "required": [
      "manifestPath"
    ],
    "$schema": "http://json-schema.org/draft-07/schema#"
  },
  "outputSchema": {
    "type": "object",
    "properties": {
      "isValid": {
        "type": "boolean",
        "description": "Whether the manifest is valid according to the UI5 Manifest schema."
      },
      "errors": {
        "type": "array",
        "items": {
          "type": "object",
          "properties": {
            "keyword": {
              "type": "string",
              "description": "Validation keyword."
            },
            "instancePath": {
              "type": "string",
              "description": "JSON Pointer to the location in the data instance (e.g., `/prop/1/subProp`)."
            },
            "schemaPath": {
              "type": "string",
              "description": "JSON Pointer to the location of the failing keyword in the schema."
            },
            "params": {
              "type": "object",
              "propertyNames": {},
              "additionalProperties": {},
              "description": "An object with additional information about the error."
            },
            "propertyName": {
              "description": "Set for errors in `propertyNames` keyword schema.",
              "type": "string"
            },
            "message": {
              "description": "The error message.",
              "type": "string"
            }
          },
          "required": [
            "keyword",
            "instancePath",
            "schemaPath",
            "params"
          ],
          "additionalProperties": false
        },
        "description": "Array of validation error objects as returned by Ajv."
      }
    },
    "required": [
      "isValid",
      "errors"
    ],
    "$schema": "http://json-schema.org/draft-07/schema#",
    "additionalProperties": false
  }
}","totalLinesInFile":74}

{"contents":"{
  "name": "run_ui5_linter",
  "description": "Run UI5 linter on a UI5 project to find and optionally fix UI5 related problems like the usage of deprecated API. After making changes, you should always run the linter again to verify that no new problems have been introduced.",
  "arguments": {
    "type": "object",
    "properties": {
      "projectDir": {
        "type": "string",
        "description": "Root directory of the UI5 project to analyze. Must be an absolute path. Typically this the directory where the 'package.json' and 'ui5.yaml' files are located."
      },
      "fix": {
        "default": false,
        "description": "Attempt to automatically correct certain findings in the files. Only the remaining findings will be returned.",
        "type": "boolean"
      },
      "filePatterns": {
        "description": "File paths or patterns to lint. If not provided, all files in the project will be linted.",
        "type": "array",
        "items": {
          "type": "string"
        }
      },
      "provideContextInformation": {
        "default": true,
        "description": "Whether to include supplementary information in the output. This includes UI5 API reference and documentation resources. When calling the tool multiple times for the same file or project, refrain from requesting additional context every time.",
        "type": "boolean"
      }
    },
    "required": [
      "projectDir"
    ],
    "$schema": "http://json-schema.org/draft-07/schema#"
  },
  "outputSchema": {
    "type": "object",
    "properties": {
      "projectDir": {
        "type": "string"
      },
      "frameworkVersion": {
        "description": "The version of UI5 used in the project",
        "type": "string"
      },
      "results": {
        "type": "array",
        "items": {
          "type": "object",
          "properties": {
            "filePath": {
              "type": "string"
            },
            "messages": {
              "type": "array",
              "items": {
                "type": "object",
                "properties": {
                  "ruleId": {
                    "type": "string"
                  },
                  "severity": {
                    "type": "number",
                    "description": "2 = error, 1 = warning"
                  },
                  "line": {
                    "type": "number"
                  },
                  "column": {
                    "type": "number"
                  },
                  "fatal": {
                    "type": "boolean"
                  },
                  "message": {
                    "type": "string"
                  },
                  "messageDetails": {
                    "type": "string"
                  }
                },
                "required": [
                  "ruleId",
                  "severity",
                  "message"
                ],
                "additionalProperties": false
              }
            }
          },
          "required": [
            "filePath",
            "messages"
          ],
          "additionalProperties": false,
          "description": "Linting results for a single file in the project"
        }
      },
      "contextInformation": {
        "type": "object",
        "properties": {
          "ruleDescriptions": {
            "type": "array",
            "items": {
              "type": "object",
              "properties": {
                "ruleId": {
                  "type": "string"
                },
                "description": {
                  "type": "string"
                }
              },
              "required": [
                "ruleId",
                "description"
              ],
              "additionalProperties": false
            },
            "description": "Brief descriptions of the rules that were found to be violated in the project"
          },
          "migrationGuides": {
            "type": "array",
            "items": {
              "type": "object",
              "properties": {
                "title": {
                  "type": "string"
                },
                "text": {
                  "type": "string"
                },
                "uri": {
                  "type": "string"
                }
              },
              "required": [
                "title",
                "text",
                "uri"
              ],
              "additionalProperties": false
            },
            "description": "For problems the linter can't fix automatically, \"fix hint\" documents may be provided as guidance for manually resolving them."
          },
          "apiReferences": {
            "type": "array",
            "items": {},
            "description": "Short extracts from the UI5 API reference for the APIs mentioned in the linter report"
          },
          "documentationResources": {
            "type": "array",
            "items": {
              "type": "object",
              "properties": {
                "title": {
                  "type": "string"
                },
                "text": {
                  "type": "string"
                },
                "uri": {
                  "type": "string"
                }
              },
              "required": [
                "title",
                "text",
                "uri"
              ],
              "additionalProperties": false
            },
            "description": "Relevant pages in the UI5 documentation that may help to understand the findings and how to resolve them best."
          }
        },
        "required": [
          "ruleDescriptions",
          "migrationGuides",
          "apiReferences",
          "documentationResources"
        ],
        "additionalProperties": false
      }
    },
    "required": [
      "projectDir",
      "results"
    ],
    "$schema": "http://json-schema.org/draft-07/schema#",
    "additionalProperties": false
  }
